(self.webpackChunk=self.webpackChunk||[]).push([[894],{5347:(e,d,r)=>{"use strict";r.r(d),r.d(d,{data:()=>a});const a={key:"v-785bcb76",path:"/docker/docker-command.html",title:"docker常用命令",lang:"en-US",frontmatter:{title:"docker常用命令"},excerpt:"",headers:[{level:3,title:"查看 Docker 版本",slug:"查看-docker-版本",children:[]},{level:3,title:"从 Docker 文件构建 Docker 映像",slug:"从-docker-文件构建-docker-映像",children:[]},{level:3,title:"运行 Docker 映像",slug:"运行-docker-映像",children:[]},{level:3,title:"查看可用的 Docker 映像",slug:"查看可用的-docker-映像",children:[]},{level:3,title:"查看最近的运行容器",slug:"查看最近的运行容器",children:[]},{level:3,title:"查看所有正在运行的容器",slug:"查看所有正在运行的容器",children:[]},{level:3,title:"停止运行容器",slug:"停止运行容器",children:[]},{level:3,title:"删除一个镜像",slug:"删除一个镜像",children:[]},{level:3,title:"删除所有镜像",slug:"删除所有镜像",children:[]},{level:3,title:"强制删除所有镜像",slug:"强制删除所有镜像",children:[]},{level:3,title:"删除所有虚悬镜像",slug:"删除所有虚悬镜像",children:[]},{level:3,title:"删除所有未运行容器",slug:"删除所有未运行容器",children:[]},{level:3,title:"删除所有容器",slug:"删除所有容器",children:[]},{level:3,title:"进入 Docker 容器",slug:"进入-docker-容器",children:[]},{level:3,title:"查看所有数据卷",slug:"查看所有数据卷",children:[]},{level:3,title:"删除指定数据卷",slug:"删除指定数据卷",children:[]},{level:3,title:"删除所有未关联的数据卷",slug:"删除所有未关联的数据卷",children:[]},{level:3,title:"从主机复制文件到容器",slug:"从主机复制文件到容器",children:[]},{level:3,title:"从容器复制文件到主机",slug:"从容器复制文件到主机",children:[]}],filePathRelative:"docker/docker-command.md",git:{updatedTime:1626154667e3,contributors:[]}}},885:(e,d,r)=>{"use strict";r.r(d),r.d(d,{default:()=>c});const a=(0,r(6252).uE)('<h3 id="查看-docker-版本" tabindex="-1"><a class="header-anchor" href="#查看-docker-版本" aria-hidden="true">#</a> 查看 Docker 版本</h3><p><code>docker version</code></p><h3 id="从-docker-文件构建-docker-映像" tabindex="-1"><a class="header-anchor" href="#从-docker-文件构建-docker-映像" aria-hidden="true">#</a> 从 Docker 文件构建 Docker 映像</h3><p><code>docker build -t image-name docker-file-location</code></p><h3 id="运行-docker-映像" tabindex="-1"><a class="header-anchor" href="#运行-docker-映像" aria-hidden="true">#</a> 运行 Docker 映像</h3><p><code>docker run -d image-name</code></p><h3 id="查看可用的-docker-映像" tabindex="-1"><a class="header-anchor" href="#查看可用的-docker-映像" aria-hidden="true">#</a> 查看可用的 Docker 映像</h3><p><code>docker images</code></p><h3 id="查看最近的运行容器" tabindex="-1"><a class="header-anchor" href="#查看最近的运行容器" aria-hidden="true">#</a> 查看最近的运行容器</h3><p><code>docker ps -l</code></p><h3 id="查看所有正在运行的容器" tabindex="-1"><a class="header-anchor" href="#查看所有正在运行的容器" aria-hidden="true">#</a> 查看所有正在运行的容器</h3><p><code>docker ps -a</code></p><h3 id="停止运行容器" tabindex="-1"><a class="header-anchor" href="#停止运行容器" aria-hidden="true">#</a> 停止运行容器</h3><p><code>docker stop container_id</code></p><h3 id="删除一个镜像" tabindex="-1"><a class="header-anchor" href="#删除一个镜像" aria-hidden="true">#</a> 删除一个镜像</h3><p><code>docker rmi image-name</code></p><h3 id="删除所有镜像" tabindex="-1"><a class="header-anchor" href="#删除所有镜像" aria-hidden="true">#</a> 删除所有镜像</h3><p><code>docker rmi $(docker images -q)</code></p><h3 id="强制删除所有镜像" tabindex="-1"><a class="header-anchor" href="#强制删除所有镜像" aria-hidden="true">#</a> 强制删除所有镜像</h3><p><code>docker rmi -r $(docker images -q)</code></p><h3 id="删除所有虚悬镜像" tabindex="-1"><a class="header-anchor" href="#删除所有虚悬镜像" aria-hidden="true">#</a> 删除所有虚悬镜像</h3><p><code>docker rmi $(docker images -q -f dangling=true)</code></p><h3 id="删除所有未运行容器" tabindex="-1"><a class="header-anchor" href="#删除所有未运行容器" aria-hidden="true">#</a> 删除所有未运行容器</h3><p><code>sudo docker container prune</code></p><h3 id="删除所有容器" tabindex="-1"><a class="header-anchor" href="#删除所有容器" aria-hidden="true">#</a> 删除所有容器</h3><p><code>docker rm $(docker ps -a -q)</code></p><h3 id="进入-docker-容器" tabindex="-1"><a class="header-anchor" href="#进入-docker-容器" aria-hidden="true">#</a> 进入 Docker 容器</h3><p><code>docker exec -it container-id /bin/bash</code></p><h3 id="查看所有数据卷" tabindex="-1"><a class="header-anchor" href="#查看所有数据卷" aria-hidden="true">#</a> 查看所有数据卷</h3><p><code>docker volume ls</code></p><h3 id="删除指定数据卷" tabindex="-1"><a class="header-anchor" href="#删除指定数据卷" aria-hidden="true">#</a> 删除指定数据卷</h3><p><code>docker volume rm [volume_name]</code></p><h3 id="删除所有未关联的数据卷" tabindex="-1"><a class="header-anchor" href="#删除所有未关联的数据卷" aria-hidden="true">#</a> 删除所有未关联的数据卷</h3><p><code>docker volume rm $(docker volume ls -qf dangling=true)</code></p><h3 id="从主机复制文件到容器" tabindex="-1"><a class="header-anchor" href="#从主机复制文件到容器" aria-hidden="true">#</a> 从主机复制文件到容器</h3><p><code>sudo docker cp host_path containerID:container_path</code></p><h3 id="从容器复制文件到主机" tabindex="-1"><a class="header-anchor" href="#从容器复制文件到主机" aria-hidden="true">#</a> 从容器复制文件到主机</h3><p><code>sudo docker cp containerID:container_path host_path</code></p>',38),c={render:function(e,d){return a}}}}]);